import '../App.js'
import '../App.css';
import img from '../img/DSC_1614.JPG';
import React, { Component, useState } from 'react';
import Cart from './Cart.js';
import Product from './Product.js';
import data from './Data.js';

function Banner(props) {
  const [addItem, setAddItem] = useState(0)

  const add = () => {
    setAddItem(addItem + 1)
  }
  const [addCart, setAddCart] = useState([])

  

  const addToCart = (data,index) => {
    setAddCart([...addCart,data]);
    console.log(data,index)
  }
  const removeItem=(cartItem)=>{

    
    setAddCart([cartItem])
   console.log(cartItem)
  }
  const totalPrice=()=>{

  }

  return (
    <div className="banner">
      <>
        <section className='banner'>
          <div className="container">
            <div className='header'>
            <div className='d-flex align-items-center justify-content-between py-5'>
                    <h1 >hello my name is {props.value} </h1>
                    <h1>{addItem}</h1>
                  </div>
            </div>
            <div className='row complex'>
              <div className='col-md-8'>
                <div>
                
                  <div className='row'>
                    {
                      data.productData.map((item, index) => {
                        return (
                          <>
                            <div className='col-md-3 py-3' >
                              <Product imgValue={item.img} price={item.price} id={item.id} />
                              <button onClick={() => addToCart(item,index)}>add</button>
                            </div>
                          </>
                        )
                      })
}
                  </div>
                </div>
              </div>
              <div className='col-md-4'>
                {/* <Cart CartImg={img}/> */}
                <div>
{
  addCart.map((cartItem,cartIndex)=>{
    return(
      <>
       <Cart CartImg={cartItem.img} CartPrice={cartItem.price} />
       <div >
   <div className='buy'>
<button className='w-100'>buy now</button>
   </div>
   <div className='remove-item'>
   <button className='w-100' onClick={()=>removeItem(cartItem)}>remove item</button>
   </div>

   </div>
   
      </>
    )
  })
  
}
<div className='remove-item'>
  <h5 className='mb-0'>total price : {
    addCart.map((item)=>{
      return(
      item.price
      )
    }).reduce((currValue,updatedValue)=>{
      return(
      currValue+updatedValue)
    })
  }</h5>
 
   </div>
                 
                </div>
                
              </div>
            </div>
          </div>
        </section  >




      </>
    </div>
  );
}

export default Banner;
